class Solution:
    def countHillValley(self, nums):
        n = len(nums)
        count = 0
        for i in range(1, n - 1):
            if nums[i] == nums[i - 1]:
                continue
            left = None
            for j in range(i - 1, -1, -1):
                if nums[j] != nums[i]:
                    left = nums[j]
                    break
            right = None
            for j in range(i + 1, n):
                if nums[j] != nums[i]:
                    right = nums[j]
                    break
            if left is None or right is None:
                continue
            if nums[i] > left and nums[i] > right:
                count += 1
            elif nums[i] < left and nums[i] < right:
                count += 1
        return count

