var countHillValley = function(nums) {
    const compressed = [];
    for (const v of nums) {
        if (compressed.length === 0 || compressed[compressed.length - 1] !== v) {
            compressed.push(v);
        }
    }
    let count = 0;
    for (let i = 1; i < compressed.length - 1; i++) {
        if (compressed[i] > compressed[i - 1] && compressed[i] > compressed[i + 1]) {
            count++;
        } else if (compressed[i] < compressed[i - 1] && compressed[i] < compressed[i + 1]) {
            count++;
        }
    }
    return count;
